#!/usr/bin/env python3
# Beautiful T logo based on clean T shape:
# - Rich gradient: warm gold/amber stem, muted lavender crossbar
# - Soft layered glow: 3 glow passes (outer/mid/inner) for ethereal depth
# - Floating particles in warm gold
# - Subtle ambient circle behind
# - Transparent background
svg='<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 512"><defs><linearGradient id="stem" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stop-color="#F5C87A"/><stop offset="45%" stop-color="#E8A84A"/><stop offset="100%" stop-color="#C47D35"/></linearGradient><linearGradient id="bar" x1="0" y1="0" x2="1" y2="0"><stop offset="0%" stop-color="#D4B483"/><stop offset="50%" stop-color="#E8C99B"/><stop offset="100%" stop-color="#D4B483"/></linearGradient><radialGradient id="halo" cx="50%" cy="42%" r="45%"><stop offset="0%" stop-color="#F5D98A" stop-opacity="0.18"/><stop offset="100%" stop-color="#F5D98A" stop-opacity="0"/></radialGradient><filter id="og" x="-100%" y="-100%" width="300%" height="300%"><feGaussianBlur stdDeviation="18" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter><filter id="mg" x="-80%" y="-80%" width="260%" height="260%"><feGaussianBlur stdDeviation="10" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter><filter id="ig" x="-50%" y="-50%" width="200%" height="200%"><feGaussianBlur stdDeviation="4" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter></defs><rect width="512" height="512" fill="none"/><ellipse cx="256" cy="230" rx="175" ry="165" fill="url(#halo)"/><ellipse cx="256" cy="218" rx="110" ry="105" fill="none" stroke="#E8C99B" stroke-width="0.8" opacity="0.1"/><circle cx="148" cy="148" r="72" fill="none" stroke="#E8C99B" stroke-width="0.6" opacity="0.08"/><circle cx="364" cy="148" r="56" fill="none" stroke="#F5C87A" stroke-width="0.6" opacity="0.07"/><circle cx="128" cy="310" r="48" fill="none" stroke="#D4B483" stroke-width="0.6" opacity="0.07"/><circle cx="384" cy="310" r="64" fill="none" stroke="#E8C99B" stroke-width="0.6" opacity="0.06"/><path d="M132,260C160,230 210,210 256,210C302,210 352,230 380,260" fill="none" stroke="#F5C87A" stroke-width="14" stroke-linecap="round" opacity="0.2" filter="url(#og)"/><path d="M128,260C156,230 210,210 256,210C302,210 356,230 384,260" fill="none" stroke="#E8C99B" stroke-width="18" stroke-linecap="round" opacity="0.3" filter="url(#mg)"/><path d="M124,260C152,230 210,210 256,210C302,210 360,230 388,260" fill="none" stroke="#D4B483" stroke-width="26" stroke-linecap="round" opacity="0.95"/><path d="M124,260C152,230 210,210 256,210C302,210 360,230 388,260" fill="none" stroke="#F5C87A" stroke-width="6" stroke-linecap="round" opacity="0.5"/><rect x="244" y="212" width="24" height="268" fill="#C47D35" opacity="0.95"/><rect x="244" y="212" width="24" height="268" fill="none" stroke="#F5C87A" stroke-width="2" opacity="0.4"/><rect x="244" y="212" width="24" height="80" fill="#F5C87A" opacity="0.25" filter="url(#ig)"/><circle cx="180" cy="188" r="3" fill="#F5C87A" opacity="0.75" filter="url(#mg)"/><circle cx="332" cy="172" r="2.5" fill="#E8C99B" opacity="0.7" filter="url(#mg)"/><circle cx="372" cy="308" r="2.5" fill="#D4B483" opacity="0.65" filter="url(#mg)"/><circle cx="140" cy="308" r="2" fill="#E8C99B" opacity="0.6" filter="url(#mg)"/><circle cx="200" cy="150" r="1.5" fill="#F5C87A" opacity="0.5"/><circle cx="312" cy="145" r="1.5" fill="#D4B483" opacity="0.45"/><circle cx="350" cy="380" r="1.5" fill="#F5C87A" opacity="0.4"/><circle cx="162" cy="380" r="1.5" fill="#E8C99B" opacity="0.4"/><circle cx="420" cy="210" r="2" fill="#D4B483" opacity="0.3"/><circle cx="92" cy="210" r="2" fill="#E8C99B" opacity="0.3"/></svg>'
with open('logo.svg','w',encoding='utf-8') as f: f.write(svg)
